// Normalize email — supports Outlook (from.emailAddress.address) and IMAP (from string)
const results = [];

for (const item of $input.all()) {
  const fromRaw = item.json.from;
  const fromAddr = typeof fromRaw === 'object'
    ? (fromRaw?.emailAddress?.address || fromRaw?.address || '')
    : (fromRaw || '');

  const emailData = {
    from: fromAddr,
    to: item.json.toRecipients?.[0]?.emailAddress?.address || item.json.to || '',
    subject: item.json.subject || '',
    date: item.json.receivedDateTime || item.json.date || new Date().toISOString(),
    messageId: item.json.id || (item.json.headers ? item.json.headers['message-id'] : ''),
    text: item.json.body?.content || item.json.text || item.json.textAsHtml || item.json.html || '',
    hasAttachment: item.json.hasAttachments || false,
    uid: item.json.id || (item.json.attributes ? item.json.attributes.uid : null)
  };

  if (item.binary && Object.keys(item.binary).length > 0) {
    emailData.hasAttachment = true;
  }

  results.push({ json: emailData, binary: item.binary || {} });
}

return results;

// Filter: Only emails with PDF attachments
const results = [];

for (const item of $input.all()) {
  if (!item.json.hasAttachment) continue;

  const hasPDF = Object.values(item.binary || {}).some(a =>
    a.mimeType === 'application/pdf' || a.fileName?.toLowerCase().endsWith('.pdf')
  );

  if (hasPDF) results.push(item);
}

return results;

// Split each PDF attachment into its own item
const results = [];

for (const item of $input.all()) {
  for (const key of Object.keys(item.binary || {})) {
    const bin = item.binary[key];
    if (bin.mimeType === 'application/pdf' || (bin.fileName || '').toLowerCase().endsWith('.pdf')) {
      results.push({
        json: {
          fileName: bin.fileName || 'document.pdf',
          emailSubject: item.json.subject || '',
          emailFrom: item.json.from || '',
          emailDate: item.json.date || ''
        },
        binary: { data: bin }
      });
    }
  }
}

return results;

