// Parse Gemini Invoice OCR → QuickEnergy rechnungen schema
let invoice;
try {
  const raw = $input.first().json.candidates[0].content.parts[0].text;
  invoice = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch(e) {
  throw new Error('Gemini OCR parse error: ' + e.message);
}

if (invoice.is_storno) {
  if (invoice.invoice_amount > 0) invoice.invoice_amount = -Math.abs(invoice.invoice_amount);
  if (invoice.invoice_net_amount > 0) invoice.invoice_net_amount = -Math.abs(invoice.invoice_net_amount);
}

function normalizeDate(raw) {
  if (!raw) return null;
  const s = String(raw).trim();
  if (s.includes('.')) {
    const [d, m, y] = s.split('.');
    if (y && m && d) return `${y.trim()}-${m.trim().padStart(2,'0')}-${d.trim().padStart(2,'0')}`;
  }
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  const p = new Date(s);
  return isNaN(p.getTime()) ? null : p.toISOString().split('T')[0];
}

const pdfBinary = $('Split PDF Attachments').first().binary || {};

return [{
  json: {
    rechnungsnr:    invoice.invoice_number || `EMAIL-${Date.now().toString(36).toUpperCase()}`,
    betrag:         invoice.invoice_net_amount || invoice.invoice_amount || 0,
    ust_satz:       Number(invoice.invoice_tax_rate || 20),
    faelligkeit:    normalizeDate(invoice.invoice_due_date),
    skonto_datum:   normalizeDate(invoice.skonto_due_date),
    skonto_prozent: invoice.skonto_percent || null,
    status:         'eingegangen',
    ocr_json:       invoice
  },
  binary: pdfBinary
}];

// Parse Gemini Receipt OCR → QuickEnergy rechnungen schema
let receipt;
try {
  const raw = $input.first().json.candidates[0].content.parts[0].text;
  receipt = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch(e) {
  throw new Error('Gemini OCR parse error: ' + e.message);
}

function normalizeDate(raw) {
  if (!raw) return null;
  const s = String(raw).trim();
  if (s.includes('.')) {
    const [d, m, y] = s.split('.');
    if (y && m && d) return `${y.trim()}-${m.trim().padStart(2,'0')}-${d.trim().padStart(2,'0')}`;
  }
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  const p = new Date(s);
  return isNaN(p.getTime()) ? null : p.toISOString().split('T')[0];
}

// Determine dominant tax rate
const net20 = Number(receipt.tax_20_net || 0);
const net10 = Number(receipt.tax_10_net || 0);
const dominantRate = net20 >= net10 ? 20 : 10;

// Netto = sum of tax-exclusive amounts, or derive from total
const nettoTotal = (net20 + net10) || Number(receipt.total_without_tip || receipt.total_amount || 0);

const pdfBinary = $('Split PDF Attachments').first().binary || {};

return [{
  json: {
    rechnungsnr:    receipt.receipt_number || `BELEG-${Date.now().toString(36).toUpperCase()}`,
    betrag:         nettoTotal,
    ust_satz:       dominantRate,
    faelligkeit:    normalizeDate(receipt.receipt_date),
    skonto_datum:   null,
    skonto_prozent: null,
    status:         'eingegangen',
    ocr_json:       receipt
  },
  binary: pdfBinary
}];

const parsed = $('Parse Invoice for QuickEnergy').first().json;
const uploadResult = $input.first().json;
const storageKey = uploadResult.Key || uploadResult.path || null;
const pdfUrl = storageKey
  ? `https://emrjxrtxlvyrwplglkzk.supabase.co/storage/v1/object/public/${storageKey}`
  : null;
return [{ json: { ...parsed, pdf_url: pdfUrl } }];

